1	//! h2 configuration and the log-linear index math.
2	//!
3	//! - `Config` holds the two powers `(grouping_power,
4	//!   max_value_power)` and derives everything else as
5	//!   `const fn`: bucket count, value→index, index→value range.
6	//! - The scheme: values below `2^(g+1)` are exact (width-1
7	//!   buckets); each power-of-two range above holds `2^g`
8	//!   equal-width buckets, so relative error ≤ `2^-g`.
9	
10	/// Errors from configuration validation.
11	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
12	pub enum Error {
13	    /// `max_value_power` is outside `1..=64`.
14	    MaxValuePower,
15	    /// `grouping_power` is not below `max_value_power`, or
16	    /// exceeds 62 (keeps every internal shift in u64 range).
17	    GroupingPower,
18	    /// `(n - g + 1) << g` exceeds `u32::MAX` buckets — far
19	    /// beyond any practical footprint.
20	    TooManyBuckets,
21	    /// Counts storage length differs from
22	    /// `Config::total_buckets()`.
23	    StorageLen,
24	    /// Operation requires identical configs (e.g. merge).
25	    ConfigMismatch,
26	}
27	
28	/// The two h2 powers plus the index math they induce.
29	///
30	/// - `grouping_power` (g): `2^g` buckets per power-of-two
31	///   range; relative value error ≤ `2^-g`.
32	/// - `max_value_power` (n): max trackable value is `2^n - 1`;
33	///   larger values clamp into the top bucket.
34	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
35	pub struct Config {
36	    grouping_power: u8,
37	    max_value_power: u8,
38	}
39	
40	impl Config {
41	    /// Validate and build a config; see [`Error`] for the
42	    /// rejection rules.
43	    pub const fn new(grouping_power: u8, max_value_power: u8) -> Result<Config, Error> {
44	        if max_value_power < 1 || max_value_power > 64 {
45	            return Err(Error::MaxValuePower);
46	        }
47	        if grouping_power >= max_value_power || grouping_power > 62 {
48	            return Err(Error::GroupingPower);
49	        }
50	        let buckets = ((max_value_power - grouping_power) as u64 + 1) << grouping_power;
51	        if buckets > u32::MAX as u64 {
52	            return Err(Error::TooManyBuckets);
53	        }
54	        Ok(Config {
55	            grouping_power,
56	            max_value_power,
57	        })
58	    }
59	
60	    /// The grouping power g.
61	    #[inline]
62	    pub const fn grouping_power(&self) -> u8 {
63	        self.grouping_power
64	    }
65	
66	    /// The max value power n.
67	    #[inline]
68	    pub const fn max_value_power(&self) -> u8 {
69	        self.max_value_power
70	    }
71	
72	    /// Largest trackable value, `2^n - 1`.
73	    #[inline]
74	    pub const fn max_value(&self) -> u64 {
75	        u64::MAX >> (64 - self.max_value_power as u32)
76	    }
77	
78	    /// Number of buckets, `(n - g + 1) * 2^g` — the exact
79	    /// counts-storage length this config requires.
80	    #[inline]
81	    pub const fn total_buckets(&self) -> usize {
82	        (((self.max_value_power - self.grouping_power) as usize) + 1) << self.grouping_power
83	    }
84	
