109	    /// Inclusive value range `(low, high)` of a bucket index.
110	    ///
111	    /// Callers must pass `index < total_buckets()`; the math
112	    /// is meaningless beyond it (no panic, garbage range).
113	    #[inline]
114	    pub const fn value_range(&self, index: usize) -> (u64, u64) {
115	        if index < (1usize << (self.grouping_power + 1)) {
116	            return (index as u64, index as u64);
117	        }
118	        let log_bucket = (index >> self.grouping_power) as u8 - 1;
119	        let m = index - ((log_bucket as usize) << self.grouping_power);
120	        let low = (m as u64) << log_bucket;
121	        (low, low + ((1u64 << log_bucket) - 1))
122	    }
123	}
