1	//! The borrowed-storage histogram and its record path.
2	//!
3	//! - `Histogram` borrows its counts slice from the caller
4	//!   (static buffer, stack array, or heap under `std`), so
5	//!   storage stays detachable — the future buffer-swap
6	//!   servicing model needs exactly that.
7	//! - `record` is the one hot operation: index (a compare, a
8	//!   clz, two shifts) and a saturating increment. No floats,
9	//!   no allocation, no panics.
10	
11	use crate::analysis::{Buckets, merge_into, quantile_of};
12	use crate::config::{Config, Error};
13	use crate::counter::Counter;
14	
15	/// Shared record-path core for the borrowed and owned types:
16	/// index `value`, saturating-add `n` into its bucket. Nothing
17	/// else — totals are computed at read time so the hot path
18	/// stays minimal. The `get_mut` guard makes the panic path
19	/// unreachable (index invariant proven by the config tests).
20	#[inline]
21	pub(crate) fn record_into<C: Counter>(config: &Config, counts: &mut [C], value: u64, n: u64) {
22	    let idx = config.index_for(value);
23	    if let Some(c) = counts.get_mut(idx) {
24	        *c = c.sat_add(n);
25	    }
26	}
27	
28	/// Saturating sum of a counts slice — the read-time `total`
29	/// shared by the borrowed and owned types.
30	pub(crate) fn total_of<C: Counter>(counts: &[C]) -> u64 {
31	    let mut total = 0u64;
32	    for c in counts {
33	        total = total.saturating_add(c.to_u64());
34	    }
35	    total
36	}
37	
38	/// A log-linear histogram over caller-supplied counts storage.
39	///
40	/// - `config` — the h2 powers and index math.
41	/// - `counts` — exactly `config.total_buckets()` counters.
42	/// - No derived state: totals are computed from the counts at
43	///   read time, keeping the record path minimal.
44	#[derive(Debug)]
45	pub struct Histogram<'a, C: Counter = u32> {
46	    config: Config,
47	    counts: &'a mut [C],
48	}
49	
50	impl<'a, C: Counter> Histogram<'a, C> {
51	    /// Bind a config to its counts storage.
52	    ///
53	    /// - `counts.len()` must equal `config.total_buckets()`
54	    ///   ([`Error::StorageLen`] otherwise).
55	    /// - Storage is not zeroed here: pre-zeroed storage (or a
56	    ///   reused slice from a previous run) is the caller's
57	    ///   contract; totals are read from the counts on demand,
58	    ///   so a handed-back slice is consistent as-is.
59	    pub fn new(config: Config, counts: &'a mut [C]) -> Result<Self, Error> {
60	        if counts.len() != config.total_buckets() {
61	            return Err(Error::StorageLen);
62	        }
63	        Ok(Histogram { config, counts })
64	    }
65	
66	    /// The config this histogram was built with.
67	    pub fn config(&self) -> Config {
68	        self.config
69	    }
70	
71	    /// Saturating sum of all bucket counts. O(buckets):
72	    /// computed at read time to keep the record path minimal,
73	    /// so a saturated counter's overflow is not reflected here.
74	    pub fn total(&self) -> u64 {
75	        total_of(self.counts)
76	    }
77	
78	    /// Record one occurrence of `value`. O(1), never panics;
79	    /// over-range values clamp into the top bucket and a full
80	    /// counter saturates.
81	    #[inline]
82	    pub fn record(&mut self, value: u64) {
83	        self.record_n(value, 1);
84	    }
85	
86	    /// Record `n` occurrences of `value`; same semantics as
87	    /// [`record`](Histogram::record).
88	    #[inline]
89	    pub fn record_n(&mut self, value: u64, n: u64) {
90	        record_into(&self.config, self.counts, value, n);
91	    }
92	
93	    /// Count in bucket `index`, widened to u64; `None` past
94	    /// the last bucket.
95	    pub fn count_at(&self, index: usize) -> Option<u64> {
96	        self.counts.get(index).map(|c| c.to_u64())
97	    }
98	
99	    /// Release the borrow and hand the counts slice back —
100	    /// the swap-model hand-off shape.
101	    pub fn into_counts(self) -> &'a mut [C] {
102	        self.counts
103	    }
104	
105	    /// Iterate every bucket lowest-first, with cumulative
106	    /// counts (the band-table building block).
107	    pub fn buckets(&self) -> Buckets<'_, C> {
108	        Buckets::new(self.config, self.counts)
109	    }
110	
111	    /// Value at quantile `q` in `[0.0, 1.0]`: the upper
112	    /// bound of the bucket holding the rank-`ceil(q·total)`
113	    /// value (hdrhistogram's highest-equivalent convention,
114	    /// one-sided error ≤ 2⁻ᵍ). `None` when empty or `q` is
115	    /// out of range (NaN included).
116	    pub fn quantile(&self, q: f64) -> Option<u64> {
117	        quantile_of(&self.config, self.counts, q)
118	    }
119	
120	    /// Merge `other`'s counts into `self` (saturating);
121	    /// configs must be identical.
122	    pub fn merge_from(&mut self, other: &Histogram<'_, C>) -> Result<(), Error> {
123	        merge_into(&self.config, self.counts, &other.config, other.counts)
124	    }
125	}
126	
127	#[cfg(test)]
128	#[allow(clippy::unwrap_used)] // OK: tests panic on setup failure by design
129	mod tests {
130	    use super::*;
131	
132	    /// A (config, storage) pair for tests.
133	    fn cfg(g: u8, n: u8) -> Config {
134	        Config::new(g, n).unwrap()
135	    }
136	
137	    #[test]
138	    fn storage_len_checked() {
139	        let c = cfg(2, 8);
140	        let mut too_short = [0u32; 3];
141	        assert!(matches!(
142	            Histogram::new(c, &mut too_short),
143	            Err(Error::StorageLen)
144	        ));
145	        let mut right = [0u32; 28]; // (8-2+1)<<2
146	        assert!(Histogram::new(c, &mut right).is_ok());
147	    }
148	
149	    #[test]
150	    fn record_exact_region() {
151	        let c = cfg(3, 10);
152	        let mut counts = [0u32; 64];
153	        let mut h = Histogram::new(c, &mut counts).unwrap();
154	        h.record(0);
155	        h.record(5);
156	        h.record(5);
157	        assert_eq!(h.total(), 3);
158	        assert_eq!(h.count_at(0), Some(1));
159	        assert_eq!(h.count_at(5), Some(2));
160	        assert_eq!(h.count_at(6), Some(0));
161	    }
162	
163	    #[test]
164	    fn record_n_and_clamp() {
165	        let c = cfg(2, 8);
166	        let mut counts = [0u32; 28];
167	        let mut h = Histogram::new(c, &mut counts).unwrap();
168	        h.record_n(1_000_000, 7); // way over max_value = 255
169	        assert_eq!(h.total(), 7);
170	        assert_eq!(h.count_at(c.total_buckets() - 1), Some(7));
171	    }
172	
173	    #[test]
174	    fn counter_saturates_not_wraps() {
175	        let c = cfg(0, 1); // 2 buckets, minimal config
176	        let mut counts = [u8::MAX - 1, 0u8];
177	        let mut h = Histogram::new(c, &mut counts).unwrap();
178	        h.record(0);
179	        h.record(0);
180	        h.record(0);
181	        assert_eq!(h.count_at(0), Some(u8::MAX as u64));
182	        // total is the sum of counts, so it saturates with them.
183	        assert_eq!(h.total(), u8::MAX as u64);
184	    }
185	
186	    #[test]
187	    fn rebind_total_from_counts() {
188	        let c = cfg(2, 8);
189	        let mut counts = [0u32; 28];
190	        {
191	            let mut h = Histogram::new(c, &mut counts).unwrap();
192	            h.record(3);
193	            h.record(200);
194	        }
195	        // Rebind the same storage: total reads the counts.
196	        let h = Histogram::new(c, &mut counts).unwrap();
197	        assert_eq!(h.total(), 2);
198	    }
199	
200	    #[test]
201	    fn into_counts_hands_storage_back() {
202	        let c = cfg(2, 8);
203	        let mut counts = [0u32; 28];
204	        let mut h = Histogram::new(c, &mut counts).unwrap();
205	        h.record(3);
206	        let slice = h.into_counts();
207	        assert_eq!(slice[3], 1);
208	    }
