        let mut oracle = histogram::Histogram::new(g, n).unwrap();

        let mut rng = SplitMix64(0xDEAD_BEEF ^ ((g as u64) << 8) ^ n as u64);
        for _ in 0..50_000 {
            let v = rng.next() & cfg.max_value();
            ours.record(v);
            oracle.increment(v).unwrap();
        }

