1	//! Shared band-table renderer for tick-valued histograms.
2	//!
3	//! Both `TProbe` (fast path, direct-histogram) and `TProbe2`
4	//! (scope API, records → drain) store hardware tick deltas and
5	//! want the same band-table output shape — min/p1/…/p99/max
6	//! rows with first/last/range/count/mean columns, plus summary
7	//! lines for mean, stdev, mean min-p99, stdev min-p99. This
8	//! module provides a single implementation both can call into.
9	//!
10	//! Display unit is chosen by `as_ticks`: `false` converts stored
11	//! tick values to nanoseconds via [`crate::ticks::ticks_per_ns`];
12	//! `true` shows raw ticks.
13	
14	use hdrhistogram::Histogram;
15	
16	use crate::harness::{fmt_commas, fmt_commas_f64};
17	use crate::ticks;
18	
19	const BOUNDARY_PCTS: &[f64] = &[
20	    0.0, 0.01, 0.10, 0.20, 0.30, 0.40, 0.50, 0.60, 0.70, 0.80, 0.90, 0.99, 1.0,
21	];
22	const BOUNDARY_NAMES: &[&str] = &[
23	    "min", "p1", "p10", "p20", "p30", "p40", "p50", "p60", "p70", "p80", "p90", "p99", "max",
24	];
25	
26	/// Render a band-table report for `hist`, interpreting stored
27	/// values as hardware ticks. `kind` is the header label
28	/// (`"tprobe"`, `"tprobe2"`, …) and `name` is the probe's name.
29	/// `as_ticks=false` converts to ns; `true` keeps raw ticks.
30	/// `decimals` is the fractional-digit count on every time
31	/// column (from `--decimals`).
32	pub(crate) fn render(
33	    kind: &str,
34	    name: &str,
35	    hist: &Histogram<u64>,
36	    as_ticks: bool,
37	    decimals: usize,
38	) {
39	    let sample_count = hist.len();
40	    println!("  {kind}: {name} [count={}]", fmt_commas(sample_count));
41	    if sample_count == 0 {
42	        println!();
43	        return;
44	    }
45	
46	    let unit = if as_ticks { "tk" } else { "ns" };
47	    let tpn = ticks::ticks_per_ns();
48	    let conv = |v: u64| -> f64 { if as_ticks { v as f64 } else { v as f64 / tpn } };
49	    let conv_f = |v: f64| -> f64 { if as_ticks { v } else { v / tpn } };
50	
51	    let n_bands = BOUNDARY_PCTS.len() - 1;
52	    let mut band_first = vec![u64::MAX; n_bands];
53	    let mut band_last = vec![0u64; n_bands];
54	    let mut band_count = vec![0u64; n_bands];
55	    let mut band_sum = vec![0u128; n_bands];
56	
57	    let mut cumulative = 0u64;
58	    for iv in hist.iter_recorded() {
59	        let value = iv.value_iterated_to();
60	        let count = iv.count_at_value();
61	        let mid_rank = (cumulative as f64 + count as f64 / 2.0) / sample_count as f64;
62	        let idx = BOUNDARY_PCTS[1..]
63	            .iter()
64	            .position(|&b| mid_rank < b)
65	            .unwrap_or(n_bands - 1);
66	        band_first[idx] = band_first[idx].min(value);
67	        band_last[idx] = band_last[idx].max(value);
68	        band_count[idx] += count;
69	        band_sum[idx] += value as u128 * count as u128;
70	        cumulative += count;
71	    }
72	
73	    struct BandRow {
74	        label: String,
75	        first: String,
76	        last: String,
77	        range: String,
78	        count: String,
79	        mean: String,
80	    }
81	
82	    let mut rows: Vec<BandRow> = Vec::new();
83	    for i in 0..n_bands {
84	        if band_count[i] == 0 {
85	            continue;
86	        }
87	        let mean_val = band_sum[i] as f64 / band_count[i] as f64;
88	        let range_raw = band_last[i] - band_first[i] + 1;
89	        rows.push(BandRow {
90	            label: format!("{}-{}", BOUNDARY_NAMES[i], BOUNDARY_NAMES[i + 1]),
91	            first: fmt_commas_f64(conv(band_first[i]), decimals),
92	            last: fmt_commas_f64(conv(band_last[i]), decimals),
93	            range: fmt_commas_f64(conv(range_raw), decimals),
94	            count: fmt_commas(band_count[i]),
95	            mean: fmt_commas_f64(conv_f(mean_val), decimals),
96	        });
97	    }
98	
99	    let label_w = rows
100	        .iter()
101	        .map(|r| r.label.len())
102	        .max()
103	        .unwrap_or(0)
104	        .max("stdev min-p99".len());
105	    let first_w = rows.iter().map(|r| r.first.len()).max().unwrap_or(0);
106	    let last_w = rows.iter().map(|r| r.last.len()).max().unwrap_or(0);
107	    let range_w = rows.iter().map(|r| r.range.len()).max().unwrap_or(0);
108	    let count_w = rows.iter().map(|r| r.count.len()).max().unwrap_or(0);
109	    let mean_w = rows.iter().map(|r| r.mean.len()).max().unwrap_or(0);
110	
111	    const INDENT: &str = "    ";
112	    const GAP: &str = "    ";
113	
114	    let first_col = INDENT.len() + label_w + 1 + first_w;
115	    let unit_len = 1 + unit.len();
116	    let last_gap = unit_len + GAP.len() + last_w;
117	    let range_gap = unit_len + GAP.len() + range_w;
118	    let count_gap = unit_len + GAP.len() + count_w;
119	    let mean_gap = GAP.len() + mean_w;
120	    println!(
121	        "{:>first_col$}{:>last_gap$}{:>range_gap$}{:>count_gap$}{:>mean_gap$}",
122	        "first", "last", "range", "count", "mean",
123	    );
124	
125	    for r in &rows {
126	        println!(
127	            "{INDENT}{:<label_w$} {:>first_w$} {unit}{GAP}{:>last_w$} {unit}{GAP}{:>range_w$} {unit}{GAP}{:>count_w$}{GAP}{:>mean_w$} {unit}",
128	            r.label, r.first, r.last, r.range, r.count, r.mean,
129	        );
130	    }
131	
132	    let hist_mean = hist.mean();
133	    let skip = first_w
134	        + unit_len
135	        + GAP.len()
136	        + last_w
137	        + unit_len
138	        + GAP.len()
139	        + range_w
140	        + unit_len
141	        + GAP.len()
142	        + count_w;
143	    println!(
144	        "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}",
145	        "mean",
146	        "",
147	        fmt_commas_f64(conv_f(hist_mean), decimals),
148	    );
149	    println!(
150	        "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}",
151	        "stdev",
152	        "",
153	        fmt_commas_f64(conv_f(hist.stdev()), decimals),
154	    );
155	
156	    let trim_count: u64 = band_count[..n_bands - 1].iter().sum();
157	    if trim_count > 0 {
158	        let trim_sum: u128 = band_sum[..n_bands - 1].iter().sum();
159	        let trim_mean = trim_sum as f64 / trim_count as f64;
160	
161	        let mut trim_var_sum = 0.0f64;
162	        let mut trim_var_count = 0u64;
163	        let mut cum = 0u64;
164	        for iv in hist.iter_recorded() {
165	            let value = iv.value_iterated_to();
166	            let count = iv.count_at_value();
167	            let mid_rank = (cum as f64 + count as f64 / 2.0) / sample_count as f64;
168	            let idx = BOUNDARY_PCTS[1..]
169	                .iter()
170	                .position(|&b| mid_rank < b)
171	                .unwrap_or(n_bands - 1);
172	            if idx < n_bands - 1 {
173	                let diff = value as f64 - trim_mean;
174	                trim_var_sum += diff * diff * count as f64;
175	                trim_var_count += count;
176	            }
177	            cum += count;
178	        }
179	        let trim_stdev = if trim_var_count > 1 {
180	            (trim_var_sum / trim_var_count as f64).sqrt()
181	        } else {
182	            0.0
183	        };
184	
185	        println!(
186	            "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}",
187	            "mean min-p99",
188	            "",
189	            fmt_commas_f64(conv_f(trim_mean), decimals),
190	        );
191	        println!(
192	            "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}",
193	            "stdev min-p99",
194	            "",
195	            fmt_commas_f64(conv_f(trim_stdev), decimals),
196	        );
197	    }
198	    println!();
199	}
