467	/// Format an integer with thousands separators, e.g.
468	/// `12345` → `"12,345"`.
469	pub fn fmt_commas(n: u64) -> String {
470	    let s = n.to_string();
471	    let mut result = String::new();
472	    for (i, c) in s.chars().rev().enumerate() {
473	        if i > 0 && i % 3 == 0 {
474	            result.push(',');
475	        }
476	        result.push(c);
477	    }
478	    result.chars().rev().collect()
479	}
