481	/// Format a float with `decimals` fractional digits and thousands
482	/// separators on the integer part.
483	pub fn fmt_commas_f64(n: f64, decimals: usize) -> String {
484	    let s = format!("{n:.decimals$}");
485	    let (sign, body) = match s.strip_prefix('-') {
486	        Some(rest) => ("-", rest),
487	        None => ("", s.as_str()),
488	    };
489	    let (int_part, frac_part) = match body.find('.') {
490	        Some(i) => (&body[..i], &body[i..]),
491	        None => (body, ""),
492	    };
493	    let int_num: u64 = int_part.parse().unwrap_or(0);
494	    format!("{sign}{}{frac_part}", fmt_commas(int_num))
495	}
