497	/// Index of the band containing `mid_rank`, over the full boundary
498	/// ladder `bounds` (`n_bands = bounds.len() - 1`).
499	///
500	/// - Bands are **right-closed** `(lower, upper]`: a rank exactly on a
501	///   boundary falls in the band that boundary *caps* — a single
502	///   sample's mid-rank of 0.5 lands in `p50`, not `p60`. This matches
503	///   the upper-boundary row labels and the CDF reading of a
504	///   percentile (value at or below which that fraction of samples
505	///   falls). See [`print_report`] for the convention and references.
506	/// - `mid_rank` is the Hazen plotting position `(i - 0.5) / n` of the
507	///   sample's rank, computed by the caller.
508	fn band_index(mid_rank: f64, bounds: &[bands::Boundary]) -> usize {
509	    let n_bands = bounds.len() - 1;
510	    bounds[1..]
511	        .iter()
512	        .position(|b| mid_rank <= b.pct)
513	        .unwrap_or(n_bands - 1)
514	}
