516	/// Build the trimmed-stat range label from the populated bands
517	/// below the n2 ≡ p99 tail cut.
518	///
519	/// - Names the first..last populated band in `band_count[..trim_bands]`
520	///   by its **upper** boundary (`bounds[i + 1]`), matching the row
521	///   labels — so the label tracks the real extent of the trimmed
522	///   data rather than asserting a `min` row (never printed — rows use
523	///   upper boundaries) or an `n2` band that can be empty.
524	/// - Collapses to a single name when one band holds all the trimmed
525	///   data (`p60`, not `p60..p60`).
526	/// - Empty string when no trimmed band is populated — only with no
527	///   samples at all, where the caller's `trim` is `None` and the
528	///   label goes unused.
529	fn trim_range_label(
530	    bounds: &[bands::Boundary],
531	    band_count: &[u64],
532	    trim_bands: usize,
533	    style: BandLabels,
534	) -> String {
535	    let first = (0..trim_bands).find(|&i| band_count[i] > 0);
536	    let last = (0..trim_bands).rev().find(|&i| band_count[i] > 0);
537	    match (first, last) {
538	        (Some(f), Some(l)) if f == l => bounds[f + 1].trim_name(style).to_string(),
539	        (Some(f), Some(l)) => format!(
540	            "{}..{}",
541	            bounds[f + 1].trim_name(style),
542	            bounds[l + 1].trim_name(style),
543	        ),
544	        _ => String::new(),
545	    }
546	}
