//! Constants shared by the test, bench, and demo consumers.
//!
//! - One home for every value more than one consumer depends
//!   on: the histogram config, the PRNG seed, the oracle's
//!   precision, and the synthetic stream's shape. A literal
//!   repeated across consumers can drift in one and not the
//!   others; a shared const cannot.
//! - Values only one consumer cares about — its sample count,
//!   its rep count, its own config sweep — stay with that
//!   consumer.

use h2hist::Config;

/// Seed for every deterministic stream, so the test, bench,
/// and demo all describe the same values.
pub const SEED: u64 = 42;

/// Grouping power g of the shared config: relative value error
/// ≤ 2⁻⁷ ≈ 0.78%.
pub const GROUPING_POWER: u8 = 7;

/// Max value power n of the shared config: values up to 2³⁰−1
/// ticks are trackable.
pub const MAX_VALUE_POWER: u8 = 30;

/// The config the demo, the bench, and the quantile-parity
/// test all record into.
///
/// A `const` rather than a runtime `Config::new`, so storage
/// can be sized at compile time from [`BUCKETS`] and the
/// powers cannot disagree with the printed header.
pub const CFG: Config = match Config::new(GROUPING_POWER, MAX_VALUE_POWER) {
    Ok(c) => c,
    Err(_) => panic!("dev config powers are invalid"),
};

/// Counts-storage length [`CFG`] requires — the array size for
/// a histogram over it.
pub const BUCKETS: usize = CFG.total_buckets();

/// `hdrhistogram` significant figures paired with
/// [`GROUPING_POWER`], so a comparison against it runs at like
/// precision: 2 sigfigs is ≤ 1% relative error against g=7's
/// ≤ 0.78%.
pub const HDR_SIGFIG: u8 = 2;

/// Low end of the stream's body values.
pub const BASE_LO: u64 = 50;

/// Width of the stream's uniformly-drawn body.
pub const BASE_SPAN: u64 = 100;

/// One draw in `TAIL_ODDS` leaves the body for a tail.
pub const TAIL_ODDS: u64 = 1_000;

/// Draws `1..=NEAR_TAIL_SHARE` (of [`TAIL_ODDS`]) take the
/// near tail; draw `0` takes the far tail.
pub const NEAR_TAIL_SHARE: u64 = 9;

/// Multiplier bound for the near tail.
pub const NEAR_TAIL_MULT: u64 = 100;

/// Multiplier bound for the far tail — the ~1-in-1000 samples
/// that stretch the distribution by up to four decades.
pub const FAR_TAIL_MULT: u64 = 10_000;

