                    let (low, high) = config.value_range(idx);
                    assert!(
                        low <= value && value <= high,
                        "g={grouping_power} n={max_value_power} v={value} idx={idx}"
                    );
                    if idx != prev_idx || value == 0 {
                        // First value of a bucket: partition check.
                        assert_eq!(
