                        );
                        assert_eq!(low, value, "bucket low is its first value");
                        next_expected_low = high + 1;
                    }
                    prev_idx = idx;
                }
                assert_eq!(
                    prev_idx,
                    total - 1,
                    "top value hits top bucket g={grouping_power} n={max_value_power}"
                );
                assert_eq!(
                    next_expected_low,
