mod tests {
    use super::*;

    /// Build a config at compile time; invalid powers are a
    /// test-authoring error, so they fail the build rather
    /// than the run.
    const fn cfg(g: u8, n: u8) -> Config {
        match Config::new(g, n) {
            Ok(c) => c,
            Err(_) => panic!("invalid test config"),
        }
    }

    /// The config most tests here use.
    const CFG: Config = cfg(2, 8);
    /// Counts length [`CFG`] requires — derived, so changing
    /// the powers cannot leave a stale hand-computed length.
    const BUCKETS: usize = CFG.total_buckets();

    #[test]
    fn storage_len_checked() {
        let mut too_short = [0u32; BUCKETS - 1];
        assert!(matches!(
            Histogram::new(CFG, &mut too_short),
            Err(Error::StorageLen)
        ));
        let mut right = [0u32; BUCKETS];
        assert!(Histogram::new(CFG, &mut right).is_ok());
    }

    #[test]
    fn record_exact_region() {
        const C: Config = cfg(3, 10);
        const N: usize = C.total_buckets();
        let mut counts = [0u32; N];
        let mut h = Histogram::new(C, &mut counts).unwrap();
        h.record(0);
        h.record(5);
        h.record(5);
        assert_eq!(h.total(), 3);
        assert_eq!(h.count_at(0), Some(1));
        assert_eq!(h.count_at(5), Some(2));
        assert_eq!(h.count_at(6), Some(0));
    }

    #[test]
    fn record_n_and_clamp() {
        let mut counts = [0u32; BUCKETS];
        let mut h = Histogram::new(CFG, &mut counts).unwrap();
        h.record_n(1_000_000, 7); // way over max_value = 255
        assert_eq!(h.total(), 7);
        assert_eq!(h.count_at(BUCKETS - 1), Some(7));
    }

    #[test]
    fn counter_saturates_not_wraps() {
        const C: Config = cfg(0, 1); // 2 buckets, minimal config
        let mut counts = [u8::MAX - 1, 0u8];
        let mut h = Histogram::new(C, &mut counts).unwrap();
        h.record(0);
        h.record(0);
        h.record(0);
        assert_eq!(h.count_at(0), Some(u8::MAX as u64));
        // total is the sum of counts, so it saturates with them.
        assert_eq!(h.total(), u8::MAX as u64);
    }

    #[test]
    fn rebind_total_from_counts() {
        let mut counts = [0u32; BUCKETS];
        {
            let mut h = Histogram::new(CFG, &mut counts).unwrap();
            h.record(3);
            h.record(200);
        }
        // Rebind the same storage: total reads the counts.
        let h = Histogram::new(CFG, &mut counts).unwrap();
        assert_eq!(h.total(), 2);
    }

    #[test]
    fn into_counts_hands_storage_back() {
        let mut counts = [0u32; BUCKETS];
        let mut h = Histogram::new(CFG, &mut counts).unwrap();
        h.record(3);
        let slice = h.into_counts();
        assert_eq!(slice[3], 1);
    }
}

