///     Ok(c) => c,
///     Err(_) => panic!("invalid config"),
/// };
/// let mut h = HistogramArray::<{ CFG.total_buckets() }>::new(CFG).unwrap();
/// h.record(42);
/// assert_eq!(h.total(), 1);
