1	//! The borrowed-storage histogram and its record path.
2	//!
3	//! - `Histogram` borrows its counts slice from the caller
4	//!   (static buffer, stack array, or heap under `std`), so
5	//!   storage stays detachable — the future buffer-swap
6	//!   servicing model needs exactly that.
7	//! - `record` is the one hot operation: index (a compare, a
8	//!   clz, two shifts) and a saturating increment. No floats,
9	//!   no allocation, no panics.
10	
11	use crate::analysis::{Buckets, merge_into, quantile_of};
12	use crate::config::{Config, Error};
13	use crate::counter::Counter;
14	
15	/// Shared record-path core for the borrowed and owned types:
16	/// index `value`, saturating-add `count` into its bucket.
17	/// Nothing else — totals are computed at read time so the hot
18	/// path stays minimal. The `get_mut` guard makes the panic
19	/// path unreachable (index invariant proven by the config
20	/// tests).
21	#[inline]
22	pub(crate) fn record_into<Cnt: Counter>(
23	    config: &Config,
24	    counts: &mut [Cnt],
25	    value: u64,
26	    count: u64,
27	) {
28	    let idx = config.index_for(value);
29	    if let Some(cnt) = counts.get_mut(idx) {
30	        *cnt = cnt.sat_add(count);
31	    }
32	}
33	
34	/// Saturating sum of a counts slice — the read-time `total`
35	/// shared by the borrowed and owned types.
36	pub(crate) fn total_of<Cnt: Counter>(counts: &[Cnt]) -> u64 {
37	    let mut total = 0u64;
38	    for cnt in counts {
39	        total = total.saturating_add(cnt.to_u64());
40	    }
41	    total
