44	/// A log-linear histogram over caller-supplied counts storage.
45	///
46	/// - `config` — the h2 powers and index math.
47	/// - `counts` — exactly `config.total_buckets()` counters.
48	/// - No derived state: totals are computed from the counts at
49	///   read time, keeping the record path minimal.
50	#[derive(Debug)]
51	pub struct Histogram<'a, Cnt: Counter = u32> {
52	    config: Config,
53	    counts: &'a mut [Cnt],
54	}
55	
56	impl<'a, Cnt: Counter> Histogram<'a, Cnt> {
57	    /// Bind a config to its counts storage.
58	    ///
59	    /// - `counts.len()` must equal `config.total_buckets()`
60	    ///   ([`Error::StorageLen`] otherwise).
61	    /// - Storage is not zeroed here: pre-zeroed storage (or a
62	    ///   reused slice from a previous run) is the caller's
63	    ///   contract; totals are read from the counts on demand,
64	    ///   so a handed-back slice is consistent as-is.
65	    pub fn new(config: Config, counts: &'a mut [Cnt]) -> Result<Self, Error> {
66	        if counts.len() != config.total_buckets() {
67	            return Err(Error::StorageLen);
68	        }
69	        Ok(Histogram { config, counts })
70	    }
71	
72	    /// The config this histogram was built with.
73	    pub fn config(&self) -> Config {
74	        self.config
75	    }
76	
77	    /// Saturating sum of all bucket counts. O(buckets):
78	    /// computed at read time to keep the record path minimal,
79	    /// so a saturated counter's overflow is not reflected here.
80	    pub fn total(&self) -> u64 {
81	        total_of(self.counts)
82	    }
83	
84	    /// Record one occurrence of `value`. O(1), never panics;
85	    /// over-range values clamp into the top bucket and a full
86	    /// counter saturates.
87	    #[inline]
88	    pub fn record(&mut self, value: u64) {
89	        self.record_n(value, 1);
90	    }
91	
92	    /// Record `count` occurrences of `value`; same semantics
93	    /// as [`record`](Histogram::record).
94	    #[inline]
95	    pub fn record_n(&mut self, value: u64, count: u64) {
96	        record_into(&self.config, self.counts, value, count);
97	    }
98	
99	    /// Count in bucket `index`, widened to u64; `None` past
100	    /// the last bucket.
101	    pub fn count_at(&self, index: usize) -> Option<u64> {
102	        self.counts.get(index).map(|cnt| cnt.to_u64())
103	    }
104	
105	    /// Release the borrow and hand the counts slice back —
106	    /// the swap-model hand-off shape.
107	    pub fn into_counts(self) -> &'a mut [Cnt] {
108	        self.counts
109	    }
110	
111	    /// Iterate every bucket lowest-first, with cumulative
112	    /// counts (the band-table building block).
113	    pub fn buckets(&self) -> Buckets<'_, Cnt> {
114	        Buckets::new(self.config, self.counts)
115	    }
116	
117	    /// Value at quantile `fraction` in `[0.0, 1.0]`: the upper
118	    /// bound of the bucket holding the rank-`ceil(fraction·total)`
119	    /// value (hdrhistogram's highest-equivalent convention,
120	    /// one-sided error ≤ 2⁻ᵍ). `None` when empty or `fraction`
121	    /// is out of range (NaN included).
122	    pub fn quantile(&self, fraction: f64) -> Option<u64> {
123	        quantile_of(&self.config, self.counts, fraction)
124	    }
125	
126	    /// Merge `other`'s counts into `self` (saturating);
127	    /// configs must be identical.
128	    pub fn merge_from(&mut self, other: &Histogram<'_, Cnt>) -> Result<(), Error> {
129	        merge_into(&self.config, self.counts, &other.config, other.counts)
130	    }
131	}
