use h2hist::{Config, Histogram};

#[path = "../dev/mod.rs"]
mod dev;

use dev::consts::{BUCKETS, CFG, GROUPING_POWER, HDR_SIGFIG, MAX_VALUE_POWER, SEED};
use dev::rng::SplitMix64;
