/// Run all variants and print the comparison table.
fn main() -> Result<(), Error> {
    let values: Vec<u64> = HeavyTailed::new(SEED, CFG.max_value()).take(LEN).collect();

    println!(
        "record bench: g={GROUPING_POWER} n={MAX_VALUE_POWER} buckets={BUCKETS} len={LEN} reps={REPS} (best)"
    );
    println!("{:<22} {:<12} {:>9}", "variant", "stored", "ns/record");

    let mut store = vec![0u64; LEN];
    bench("raw streaming store", "u64 sample", || {
        for (slot, &v) in store.iter_mut().zip(values.iter()) {
            *slot = v;
        }
        black_box(&store);
    });

    let mut counts = [0u32; BUCKETS];
    let mut h = Histogram::new(CFG, &mut counts)?;
    bench("h2hist u32", "u32 counter", || {
        for &v in &values {
            h.record(v);
        }
        black_box(h.total());
    });

    let mut counts_t = [0u32; BUCKETS];
    let mut ht = Histogram::new(CFG, &mut counts_t)?;
    bench("h2hist u32 + total", "u32 counter", || {
        let mut total = 0u64;
        for &v in &values {
            ht.record(v);
            total = total.saturating_add(1);
        }
        black_box(total);
    });

    let mut counts64 = [0u64; BUCKETS];
    let mut h64 = Histogram::<u64>::new(CFG, &mut counts64)?;
    bench("h2hist u64", "u64 counter", || {
        for &v in &values {
            h64.record(v);
        }
        black_box(h64.total());
    });

    let mut raw_counts = [0u32; BUCKETS];
    bench("index_for + wrap u32", "u32 counter", || {
        for &v in &values {
            if let Some(c) = raw_counts.get_mut(CFG.index_for(v)) {
                *c = c.wrapping_add(1);
            }
        }
        black_box(&raw_counts);
    });

    let mut counts2 = [0u32; BUCKETS];
    let mut h2 = Histogram::new(CFG, &mut counts2)?;
    bench("h2hist u32 + extras", "u32 counter", || {
        let (mut mn, mut mx, mut sum) = (u64::MAX, 0u64, 0u64);
        for &v in &values {
            h2.record(v);
            mn = mn.min(v);
            mx = mx.max(v);
            sum = sum.wrapping_add(v);
        }
        black_box((mn, mx, sum, h2.total()));
    });

    match histogram::Histogram::new(GROUPING_POWER, MAX_VALUE_POWER) {
        Ok(mut io) => {
            bench("histogram u64", "u64 counter", || {
                for &v in &values {
                    // Values are pre-clamped, increment cannot fail.
                    let _ = io.increment(v);
                }
                black_box(&io);
            });
        }
        Err(e) => println!("histogram crate setup failed: {e:?}"),
    }

    match hdrhistogram::Histogram::<u64>::new_with_bounds(1, CFG.max_value(), HDR_SIGFIG) {
        Ok(mut hdr) => {
            bench(
                &format!("hdrhistogram {HDR_SIGFIG}sf"),
                "u64 counter",
                || {
                    for &v in &values {
                        // Values are pre-clamped, record cannot fail.
                        let _ = hdr.record(v);
                    }
                    black_box(hdr.len());
                },
            );
        }
        Err(e) => println!("hdrhistogram setup failed: {e:?}"),
    }

    Ok(())

