//! Band-boundary ladder for report tables.
//!
//! - The z/p/n ladder iiac-perf's reports use: familiar
//!   deciles in the body, nines/zeros notation in the tails —
//!   `zK`/`nK` mark the boundary with a fraction `10^-K` of
//!   samples below (z) or above (n), so n2 ≡ p99, z2 ≡ p1.
//! - `no_std`, no-alloc: fences are integer rationals
//!   (`num/den`), so a rank boundary is `total * num / den` in
//!   u128 — exact, no `floor`/`powi` — and labels are written
//!   into any `core::fmt::Write` instead of returned as
//!   strings.
//! - `Ladder` generates the boundary sequence from its two
//!   tail depths; deepening a tail is a one-argument change.

use core::fmt::{self, Write};

use crate::config::Error;

/// `10^exp`, saturating at `u64::MAX` (exp ≤ 19 is exact;
/// [`Ladder::new`] rejects deeper tails).
const fn pow10_sat(exp: u8) -> u64 {
    let mut result = 1u64;
    let mut i = 0;
    while i < exp {
        result = result.saturating_mul(10);
        i += 1;
    }
    result
}

/// One boundary of the band ladder, named by its CDF position.
///
/// - `Min` / `Max` — the ladder ends (CDF 0 and 1).
/// - `Z(k)` — fast tail: a fraction `10^-k` of samples at or
///   below it.
/// - `P(d)` — decile `d` in `1..=9`: a fraction `d/10` at or
///   below it.
/// - `N(k)` — slow tail: a fraction `10^-k` of samples above
///   it (n2 ≡ p99, n3 ≡ p99.9, …).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Boundary {
    /// CDF 0 — below every sample.
    Min,
    /// Fast tail, fraction `10^-k` at or below.
    Z(u8),
    /// Decile `d` in `1..=9`, fraction `d/10` at or below.
    P(u8),
    /// Slow tail, fraction `10^-k` above.
    N(u8),
    /// CDF 1 — at or above every sample.
    Max,
}

impl Boundary {
    /// The boundary's CDF fraction as an exact rational
    /// `(num, den)`.
    pub const fn fraction(&self) -> (u64, u64) {
        match *self {
            Boundary::Min => (0, 1),
            Boundary::Z(k) => (1, pow10_sat(k)),
            Boundary::P(d) => (d as u64, 10),
            Boundary::N(k) => {
                let den = pow10_sat(k);
                (den - 1, den)
            }
            Boundary::Max => (1, 1),
        }
    }

    /// The boundary's rank in a run of `total` samples:
    /// `floor(total * num / den)`, computed exactly in u128
    /// (no float `floor`).
    pub const fn rank(&self, total: u64) -> u64 {
        let (num, den) = self.fraction();
        ((total as u128 * num as u128) / den as u128) as u64
    }

    /// The boundary's CDF fraction as an f64, for consumers
    /// working in mid-rank space.
    pub fn pct(&self) -> f64 {
        let (num, den) = self.fraction();
        num as f64 / den as f64
    }

    /// Rendered length of the zpn name (`z4` = 2, `n10` = 3,
    /// deciles and `min`/`max` = 3) — the width the `Both`
    /// style pads to.
    const fn zpn_len(&self) -> usize {
        match *self {
            Boundary::Min | Boundary::Max | Boundary::P(_) => 3,
            Boundary::Z(k) | Boundary::N(k) => {
                if k < 10 {
                    2
                } else {
                    3
                }
            }
        }
    }

    /// Write the nines/zeros / decile name (`z3`, `p50`,
    /// `n4`, `min`).
    pub fn write_zpn<W: Write>(&self, out: &mut W) -> fmt::Result {
        match *self {
            Boundary::Min => out.write_str("min"),
            Boundary::Max => out.write_str("max"),
            Boundary::Z(k) => write!(out, "z{k}"),
            Boundary::P(d) => write!(out, "p{d}0"),
            Boundary::N(k) => write!(out, "n{k}"),
        }
    }

    /// Write the literal-fraction name with `_` grouping
    /// (`0.001`, `0.50`, `0.999_9`, `min`).
    pub fn write_frac<W: Write>(&self, out: &mut W) -> fmt::Result {
        match *self {
            Boundary::Min => out.write_str("min"),
            Boundary::Max => out.write_str("max"),
            Boundary::P(d) => write!(out, "0.{d}0"),
            Boundary::Z(k) => write_grouped(out, k, '0', true),
            Boundary::N(k) => write_grouped(out, k, '9', false),
        }
    }

    /// Write the row label in the given style.
    ///
    /// - `Both` pads the zpn name to its 3-char max so the
    ///   fraction column aligns (`n4  0.999_9`); `min`/`max`
    ///   carry no fraction, so `Both` prints them bare.
    pub fn write_label<W: Write>(&self, style: BandLabels, out: &mut W) -> fmt::Result {
        match style {
            BandLabels::Zpn => self.write_zpn(out),
            BandLabels::Frac => self.write_frac(out),
            BandLabels::Both => match *self {
                Boundary::Min | Boundary::Max => self.write_zpn(out),
                _ => {
                    self.write_zpn(out)?;
                    let mut written = self.zpn_len();
                    while written < 3 {
                        out.write_char(' ')?;
                        written += 1;
                    }
                    out.write_char(' ')?;
                    self.write_frac(out)
                }
            },
        }
    }

    /// Write the bare style-name used in a trimmed-stat range
    /// label — `Both` reuses the zpn name (`z4`, not the
    /// padded pair) so it reads cleanly in a `z4..n2` range.
    pub fn write_trim_name<W: Write>(&self, style: BandLabels, out: &mut W) -> fmt::Result {
        match style {
            BandLabels::Frac => self.write_frac(out),
            BandLabels::Zpn | BandLabels::Both => self.write_zpn(out),
        }
    }
}

/// Write `0.` then `digit_count` digits of `fill`, `_`-grouped
/// in threes; `trailing_one` replaces the last digit with `1`
/// (the zK fractions: `0.000_1`).
fn write_grouped<W: Write>(
    out: &mut W,
    digit_count: u8,
    fill: char,
    trailing_one: bool,
) -> fmt::Result {
    out.write_str("0.")?;
    let mut index = 0u8;
    while index < digit_count {
        if index > 0 && index.is_multiple_of(3) {
            out.write_char('_')?;
        }
        let last = index + 1 == digit_count;
        out.write_char(if trailing_one && last { '1' } else { fill })?;
        index += 1;
    }
    Ok(())
}

/// Band-label style for report rows.
///
/// - `Zpn` — nines/zeros + decile names (`z3`, `p50`, `n4`).
/// - `Frac` — literal boundary fractions with `_` grouping
///   (`0.001`, `0.50`, `0.999_9`).
/// - `Both` — zpn and fraction side by side (`n4  0.999_9`);
///   the juxtaposition teaches the zpn vocabulary.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BandLabels {
    /// nines/zeros + decile names.
    Zpn,
    /// Literal fractions.
    Frac,
    /// zpn and fraction side by side.
    Both,
}

impl BandLabels {
    /// Lowercase name for CLI flags and report-header
    /// metadata.
    pub const fn as_str(self) -> &'static str {
        match self {
            BandLabels::Zpn => "zpn",
            BandLabels::Frac => "frac",
            BandLabels::Both => "both",
        }
    }
}

/// The boundary ladder, generated from its two tail depths:
/// `min, z{z_depth}..z2, p10..p90, n2..n{n_depth}, max`.
///
/// - `n_depth` is typically deeper than `z_depth`: a latency
///   distribution is floored below (nothing beats the fast
///   path) and open above.
/// - Positions are generated on demand ([`get`](Ladder::get) /
///   [`iter`](Ladder::iter)) — no allocation, no stored table.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Ladder {
    z_depth: u8,
    n_depth: u8,
}

impl Ladder {
    /// Build a ladder; depths outside `2..=19` are rejected
    /// ([`Error::BandDepth`]) — below 2 the tail vanishes into
    /// the deciles, above 19 the `10^depth` fence math leaves
    /// u64.
    pub const fn new(z_depth: u8, n_depth: u8) -> Result<Ladder, Error> {
        if z_depth < 2 || z_depth > 19 || n_depth < 2 || n_depth > 19 {
            return Err(Error::BandDepth);
        }
        Ok(Ladder { z_depth, n_depth })
    }

    /// Fast-tail depth: the lowest tail boundary is
    /// `z{z_depth}`.
    pub const fn z_depth(&self) -> u8 {
        self.z_depth
    }

    /// Slow-tail depth: the highest tail boundary is
    /// `n{n_depth}`.
    pub const fn n_depth(&self) -> u8 {
        self.n_depth
    }

    /// Number of boundaries: min + (z_depth−1) z's + 9
    /// deciles + (n_depth−1) n's + max.
    pub const fn len(&self) -> usize {
        (self.z_depth as usize - 1) + (self.n_depth as usize - 1) + 11
    }

    /// Never true — a valid ladder always has min, deciles,
    /// and max ([`len`](Ladder::len) ≥ 13); present because
    /// `len` conventionally pairs with it.
    pub const fn is_empty(&self) -> bool {
        false
    }

    /// The boundary at `index` (ascending CDF), `None` past
    /// the end.
    pub const fn get(&self, index: usize) -> Option<Boundary> {
        if index == 0 {
            return Some(Boundary::Min);
        }
        let mut idx = index - 1;
        let z_count = self.z_depth as usize - 1;
        if idx < z_count {
            return Some(Boundary::Z(self.z_depth - idx as u8));
        }
        idx -= z_count;
        if idx < 9 {
            return Some(Boundary::P(idx as u8 + 1));
        }
        idx -= 9;
        let n_count = self.n_depth as usize - 1;
        if idx < n_count {
            return Some(Boundary::N(idx as u8 + 2));
        }
        if idx == n_count {
            return Some(Boundary::Max);
        }
        None
    }

    /// Iterate the boundaries lowest-CDF first.
    pub const fn iter(&self) -> LadderIter {
        LadderIter {
            ladder: *self,
            index: 0,
        }
    }
}

/// Iterator over a [`Ladder`]'s boundaries, ascending CDF.
#[derive(Debug)]
pub struct LadderIter {
    ladder: Ladder,
    index: usize,
}

impl Iterator for LadderIter {
    type Item = Boundary;

    fn next(&mut self) -> Option<Boundary> {
        let boundary = self.ladder.get(self.index)?;
        self.index += 1;
        Some(boundary)
    }

    fn size_hint(&self) -> (usize, Option<usize>) {
        let rest = self.ladder.len() - self.index;
        (rest, Some(rest))
    }
}

impl ExactSizeIterator for LadderIter {}

#[cfg(test)]
#[allow(clippy::unwrap_used)] // OK: tests panic on setup failure by design
mod tests {
    use super::*;

    /// Render a boundary's zpn name to a String.
    fn zpn(boundary: Boundary) -> String {
        let mut out = String::new();
        boundary.write_zpn(&mut out).unwrap();
        out
    }

    /// Render a boundary's frac name to a String.
    fn frac(boundary: Boundary) -> String {
        let mut out = String::new();
        boundary.write_frac(&mut out).unwrap();
        out
    }

    /// Render a boundary's row label to a String.
    fn label(boundary: Boundary, style: BandLabels) -> String {
        let mut out = String::new();
        boundary.write_label(style, &mut out).unwrap();
        out
    }

    /// The z4/n10 ladder must match iiac-perf's documented
    /// boundary list, both label styles.
    #[test]
    fn ladder_matches_iiac_perf() {
        let ladder = Ladder::new(4, 10).unwrap();
        let zpn_names: Vec<String> = ladder.iter().map(zpn).collect();
        assert_eq!(
            zpn_names,
            [
                "min", "z4", "z3", "z2", "p10", "p20", "p30", "p40", "p50", "p60", "p70", "p80",
                "p90", "n2", "n3", "n4", "n5", "n6", "n7", "n8", "n9", "n10", "max",
            ]
        );
        let frac_names: Vec<String> = ladder.iter().map(frac).collect();
        assert_eq!(
            frac_names,
            [
                "min",
                "0.000_1",
                "0.001",
                "0.01",
                "0.10",
                "0.20",
                "0.30",
                "0.40",
                "0.50",
                "0.60",
                "0.70",
                "0.80",
                "0.90",
                "0.99",
                "0.999",
                "0.999_9",
                "0.999_99",
                "0.999_999",
                "0.999_999_9",
                "0.999_999_99",
                "0.999_999_999",
                "0.999_999_999_9",
                "max",
            ]
        );
        assert_eq!(ladder.len(), 23);
        assert_eq!(ladder.iter().len(), 23);
        assert_eq!(ladder.get(23), None);
    }

    /// Fractions are exact: endpoints 0 and 1, interior
    /// strictly increasing (compared as cross-multiplied
    /// rationals, no float slack).
    #[test]
    fn fractions_exact_and_increasing() {
        let ladder = Ladder::new(4, 10).unwrap();
        assert_eq!(ladder.get(0).unwrap().fraction(), (0, 1));
        assert_eq!(ladder.get(ladder.len() - 1).unwrap().fraction(), (1, 1));
        let boundaries: Vec<Boundary> = ladder.iter().collect();
        for pair in boundaries.windows(2) {
            let (num_lo, den_lo) = pair[0].fraction();
            let (num_hi, den_hi) = pair[1].fraction();
            assert!(
                (num_lo as u128 * den_hi as u128) < (num_hi as u128 * den_lo as u128),
                "{:?} !< {:?}",
                pair[0],
                pair[1]
            );
        }
    }

    /// Rank boundaries come out exact where float floor math
    /// is only approximate.
    #[test]
    fn ranks_exact() {
        assert_eq!(Boundary::Min.rank(1_000_000), 0);
        assert_eq!(Boundary::Max.rank(1_000_000), 1_000_000);
        assert_eq!(Boundary::Z(4).rank(1_000_000), 100);
        assert_eq!(Boundary::P(5).rank(1_000_001), 500_000);
        assert_eq!(Boundary::N(2).rank(1_000), 990);
        // Huge totals stay exact via the u128 product.
        assert_eq!(Boundary::P(9).rank(u64::MAX), u64::MAX / 10 * 9 + 3);
        // n2 pct lands within a ulp of 0.99 (the trim anchor).
        assert!((Boundary::N(2).pct() - 0.99).abs() < 1e-12);
    }

    /// `Both` pads zpn to 3 and appends the fraction;
    /// min/max collapse to the bare name.
    #[test]
    fn both_label_shapes() {
        assert_eq!(label(Boundary::N(4), BandLabels::Both), "n4  0.999_9");
        assert_eq!(label(Boundary::N(10), BandLabels::Both), "n10 0.999_999_999_9");
        assert_eq!(label(Boundary::P(5), BandLabels::Both), "p50 0.50");
        assert_eq!(label(Boundary::Min, BandLabels::Both), "min");
        assert_eq!(label(Boundary::Max, BandLabels::Both), "max");
        assert_eq!(label(Boundary::Z(3), BandLabels::Zpn), "z3");
        assert_eq!(label(Boundary::Z(3), BandLabels::Frac), "0.001");
    }

    /// Trim names use the bare zpn form under `Both`.
    #[test]
    fn trim_name_bare() {
        let mut out = String::new();
        Boundary::Z(4).write_trim_name(BandLabels::Both, &mut out).unwrap();
        assert_eq!(out, "z4");
        out.clear();
        Boundary::N(2).write_trim_name(BandLabels::Frac, &mut out).unwrap();
        assert_eq!(out, "0.99");
    }

    /// Depths outside 2..=19 are rejected.
    #[test]
    fn depth_validation() {
        assert!(Ladder::new(2, 2).is_ok());
        assert!(Ladder::new(4, 19).is_ok());
        assert!(matches!(Ladder::new(1, 10), Err(Error::BandDepth)));
        assert!(matches!(Ladder::new(4, 1), Err(Error::BandDepth)));
        assert!(matches!(Ladder::new(20, 10), Err(Error::BandDepth)));
        assert!(matches!(Ladder::new(4, 20), Err(Error::BandDepth)));
    }

    /// The demo's z4/n8 depths also generate correctly (the
    /// -7 rewrite records at these depths first).
    #[test]
    fn demo_depths() {
        let ladder = Ladder::new(4, 8).unwrap();
        assert_eq!(ladder.len(), 19);
        let zpn_names: Vec<String> = ladder.iter().map(zpn).collect();
        assert_eq!(zpn_names[0], "min");
        assert_eq!(zpn_names[zpn_names.len() - 2], "n8");
        assert_eq!(zpn_names[zpn_names.len() - 1], "max");
    }
}

