106	            Boundary::Max => out.write_str("max"),
107	            Boundary::Z(k) => write!(out, "z{k}"),
108	            Boundary::P(d) => write!(out, "p{d}0"),
109	            Boundary::N(k) => write!(out, "n{k}"),
110	        }
111	    }
