130	    pub fn write_label<W: Write>(&self, style: BandLabels, out: &mut W) -> fmt::Result {
131	        match style {
132	            BandLabels::Zpn => self.write_zpn(out),
133	            BandLabels::Frac => self.write_frac(out),
134	            BandLabels::Both => match *self {
135	                Boundary::Min | Boundary::Max => self.write_zpn(out),
