//! Rendering: turn report structures into text.
//!
//! - The render side of the device/service split: `bands.rs` /
//!   `table.rs` build wire-friendly structures, this module
//!   turns them into characters. Everything writes into any
//!   `core::fmt::Write` — `no_std`-capable, no alloc — and a
//!   host caller just renders into a `String` and prints.
//! - Boundary labels live here, not on the data types: a
//!   label is presentation, and a device that ships structs
//!   never links this module's code.
//! - `render_band_table` reproduces the band-table shape the
//!   demo and iiac-perf print: header, one row per populated
//!   band (first/last/range/count/mean), then overall and
//!   tail-trimmed mean/stdev rows.

use core::fmt::{self, Write};

use crate::bands::Boundary;
use crate::table::BandTable;

/// Band-label style for report rows.
///
/// - `Zpn` — nines/zeros + decile names (`z3`, `p50`, `n4`).
/// - `Frac` — literal boundary fractions with `_` grouping
///   (`0.001`, `0.50`, `0.999_9`).
/// - `Both` — zpn and fraction side by side; the juxtaposition
///   teaches the zpn vocabulary.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BandLabels {
    /// nines/zeros + decile names.
    Zpn,
    /// Literal fractions.
    Frac,
    /// zpn and fraction side by side.
    Both,
}

impl BandLabels {
    /// Lowercase name for CLI flags and report-header
    /// metadata.
    pub const fn as_str(self) -> &'static str {
        match self {
            BandLabels::Zpn => "zpn",
            BandLabels::Frac => "frac",
            BandLabels::Both => "both",
        }
    }
}

/// Write the nines/zeros / decile name (`z3`, `p50`, `n4`,
/// `min`).
pub fn write_zpn<W: Write>(out: &mut W, boundary: Boundary) -> fmt::Result {
    match boundary {
        Boundary::Min => out.write_str("min"),
        Boundary::Max => out.write_str("max"),
        Boundary::Z(k) => write!(out, "z{k}"),
        Boundary::P(d) => write!(out, "p{d}0"),
        Boundary::N(k) => write!(out, "n{k}"),
    }
}

/// Write the literal-fraction name with `_` grouping
/// (`0.001`, `0.50`, `0.999_9`, `min`).
pub fn write_frac<W: Write>(out: &mut W, boundary: Boundary) -> fmt::Result {
    match boundary {
        Boundary::Min => out.write_str("min"),
        Boundary::Max => out.write_str("max"),
        Boundary::P(d) => write!(out, "0.{d}0"),
        Boundary::Z(k) => write_grouped(out, k, '0', true),
        Boundary::N(k) => write_grouped(out, k, '9', false),
    }
}

/// Write the single-cell row label in the given style.
///
/// - `Both` pads the zpn name to its 3-char max so the
///   fraction column aligns (`n4  0.999_9`); `min`/`max`
///   carry no fraction, so `Both` prints them bare.
pub fn write_label<W: Write>(out: &mut W, boundary: Boundary, style: BandLabels) -> fmt::Result {
    match style {
        BandLabels::Zpn => write_zpn(out, boundary),
        BandLabels::Frac => write_frac(out, boundary),
        BandLabels::Both => match boundary {
            Boundary::Min | Boundary::Max => write_zpn(out, boundary),
            _ => {
                let width = measure(|counter| write_zpn(counter, boundary));
                write_zpn(out, boundary)?;
                pad(out, 3usize.saturating_sub(width))?;
                out.write_char(' ')?;
                write_frac(out, boundary)
            }
        },
    }
}

/// Write the bare style-name used in a trimmed-stat range
/// label — `Both` reuses the zpn name (`z4`, not the padded
/// pair) so it reads cleanly in a `z4..n2` range.
pub fn write_trim_name<W: Write>(
    out: &mut W,
    boundary: Boundary,
    style: BandLabels,
) -> fmt::Result {
    match style {
        BandLabels::Frac => write_frac(out, boundary),
        BandLabels::Zpn | BandLabels::Both => write_zpn(out, boundary),
    }
}

/// Write `0.` then `digit_count` digits of `fill`, `_`-grouped
/// in threes; `trailing_one` replaces the last digit with `1`
/// (the zK fractions: `0.000_1`).
fn write_grouped<W: Write>(
    out: &mut W,
    digit_count: u8,
    fill: char,
    trailing_one: bool,
) -> fmt::Result {
    out.write_str("0.")?;
    let mut index = 0u8;
    while index < digit_count {
        if index > 0 && index.is_multiple_of(3) {
            out.write_char('_')?;
        }
        let last = index + 1 == digit_count;
        out.write_char(if trailing_one && last { '1' } else { fill })?;
        index += 1;
    }
    Ok(())
}

/// Write a non-negative integer with thousands separators,
/// `12345` → `12,345`.
pub fn write_commas<W: Write>(out: &mut W, value: u64) -> fmt::Result {
    let mut digits = [0u8; 20];
    let mut len = 0usize;
    let mut rest = value;
    loop {
        if let Some(slot) = digits.get_mut(len) {
            *slot = b'0' + (rest % 10) as u8;
        }
        len += 1;
        rest /= 10;
        if rest == 0 {
            break;
        }
    }
    let mut index = len;
    while index > 0 {
        index -= 1;
        if let Some(&digit) = digits.get(index) {
            out.write_char(digit as char)?;
        }
        if index > 0 && index.is_multiple_of(3) {
            out.write_char(',')?;
        }
    }
    Ok(())
}

/// Write a float with `decimals` fractional digits (rounded)
/// and thousands separators on the integer part. Scaled
/// integer math — no `round`/`floor` from `std`; `decimals`
/// is clamped to 18 so the scale stays in u128.
pub fn write_commas_f64<W: Write>(out: &mut W, value: f64, decimals: usize) -> fmt::Result {
    if !value.is_finite() {
        return write!(out, "{value}");
    }
    let decimals = if decimals > 18 { 18 } else { decimals };
    let negative = value < 0.0;
    if negative {
        out.write_char('-')?;
    }
    let magnitude = if negative { -value } else { value };
    let mut scale = 1u128;
    let mut index = 0;
    while index < decimals {
        scale *= 10;
        index += 1;
    }
    let scaled_f = magnitude * scale as f64 + 0.5;
    if scaled_f >= u128::MAX as f64 {
        // Absurd magnitude: plain core formatting, no commas.
        return write!(out, "{magnitude:.decimals$}");
    }
    let scaled = scaled_f as u128;
    let int_part = scaled / scale;
    let int_part = if int_part > u64::MAX as u128 {
        u64::MAX
    } else {
        int_part as u64
    };
    write_commas(out, int_part)?;
    if decimals > 0 {
        out.write_char('.')?;
        let frac_part = scaled % scale;
        let mut divisor = scale / 10;
        while divisor > 0 {
            out.write_char((b'0' + (frac_part / divisor % 10) as u8) as char)?;
            divisor /= 10;
        }
    }
    Ok(())
}

/// Character-counting sink for the measuring pass (labels and
/// numbers here are ASCII, so bytes == columns).
#[derive(Default)]
struct CountWriter {
    len: usize,
}

impl Write for CountWriter {
    fn write_str(&mut self, text: &str) -> fmt::Result {
        self.len += text.len();
        Ok(())
    }
}

/// Rendered width of whatever `write` emits.
fn measure(write: impl Fn(&mut CountWriter) -> fmt::Result) -> usize {
    let mut counter = CountWriter::default();
    let _ = write(&mut counter);
    counter.len
}

/// Write `count` spaces.
fn pad<W: Write>(out: &mut W, count: usize) -> fmt::Result {
    let mut left = count;
    while left > 0 {
        out.write_char(' ')?;
        left -= 1;
    }
    Ok(())
}

/// `sqrt` for the stdev rows. `std` uses the intrinsic;
/// without it, a bit-hack seed plus Newton steps. We think
/// the fallback is within an ulp or two of the intrinsic —
/// invisible at report decimals.
#[cfg(feature = "std")]
fn sqrt64(value: f64) -> f64 {
    if value > 0.0 { value.sqrt() } else { 0.0 }
}

/// `no_std` Newton fallback; see the `std` twin above.
#[cfg(not(feature = "std"))]
fn sqrt64(value: f64) -> f64 {
    if !(value > 0.0) {
        return 0.0;
    }
    if !value.is_finite() {
        return value;
    }
    // Halve the exponent for the seed, then converge.
    let mut guess = f64::from_bits((value.to_bits() >> 1) + 0x1FF8_0000_0000_0000);
    let mut step = 0;
    while step < 5 {
        guess = 0.5 * (guess + value / guess);
        step += 1;
    }
    guess
}

/// Column widths for [`render_band_table`], in characters.
///
/// - `zpn_width` — the (first) label cell; single-cell styles
///   put their whole label here.
/// - `frac_width` — the second label cell; used by
///   [`BandLabels::Both`], 0 otherwise.
/// - `value_width` — first / last / range / mean columns.
/// - `count_width` — the count column.
/// - `decimals` — fractional digits on the mean/stdev cells.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Layout {
    /// First (zpn) label cell width.
    pub zpn_width: usize,
    /// Second (fraction) label cell width; 0 disables it.
    pub frac_width: usize,
    /// Width of the first/last/range/mean columns.
    pub value_width: usize,
    /// Width of the count column.
    pub count_width: usize,
    /// Fractional digits on mean/stdev cells.
    pub decimals: usize,
}

impl Layout {
    /// The demo's historical fixed layout
    /// (`{:<4} {:<13} {:>14} … {:>12} {:>14}`, one decimal).
    pub const DEMO_LEGACY: Layout = Layout {
        zpn_width: 4,
        frac_width: 13,
        value_width: 14,
        count_width: 12,
        decimals: 1,
    };

    /// Measure a snug layout for `table` in `style`: widest
    /// cell per column, headers and summary rows included.
    pub fn measure<const CAP: usize>(
        table: &BandTable<CAP>,
        style: BandLabels,
        decimals: usize,
    ) -> Layout {
        let two_cell = matches!(style, BandLabels::Both);
        let mut zpn_width = 0usize;
        let mut frac_width = 0usize;
        let mut value_width = "first".len(); // widest header
        let mut count_width = "count".len();

        for (index, band) in table.bands().iter().enumerate() {
            if band.count == 0 {
                continue;
            }
            let Some(upper) = table.ladder().get(index + 1) else {
                continue;
            };
            let zpn_len = if two_cell {
                measure(|counter| write_zpn(counter, upper))
            } else {
                measure(|counter| write_label(counter, upper, style))
            };
            if zpn_len > zpn_width {
                zpn_width = zpn_len;
            }
            if two_cell && !matches!(upper, Boundary::Min | Boundary::Max) {
                let frac_len = measure(|counter| write_frac(counter, upper));
                if frac_len > frac_width {
                    frac_width = frac_len;
                }
            }
            let mean = band.weighted_sum / band.count as f64;
            for width in [
                measure(|counter| write_commas(counter, band.first)),
                measure(|counter| write_commas(counter, band.last)),
                measure(|counter| write_commas(counter, band.last - band.first)),
                measure(|counter| write_commas_f64(counter, mean, decimals)),
            ] {
                if width > value_width {
                    value_width = width;
                }
            }
            let count_len = measure(|counter| write_commas(counter, band.count));
            if count_len > count_width {
                count_width = count_len;
            }
        }

        // Summary values share the value column.
        for stats in [table.overall(), table.trimmed()] {
            for cell in [stats.mean, sqrt64(stats.variance)] {
                let width = measure(|counter| write_commas_f64(counter, cell, decimals));
                if width > value_width {
                    value_width = width;
                }
            }
        }

        // Summary labels sit across the whole label region;
        // widen the second cell (or the only cell) to fit.
        let trim_label = measure(|counter| {
            write_summary_label(counter, "stdev", table.trim_range(), style)
        });
        let region = zpn_width + if two_cell { 1 + frac_width } else { 0 };
        if trim_label > region {
            let grow = trim_label - region;
            if two_cell {
                frac_width += grow;
            } else {
                zpn_width += grow;
            }
        }

        Layout {
            zpn_width,
            frac_width: if two_cell { frac_width } else { 0 },
            value_width,
            count_width,
            decimals,
        }
    }
}

/// Write a summary-row label: the prefix alone (`mean`,
/// `stdev`), or `prefix lo..hi` over the trim extent
/// (collapsed to one name when the extent is a single band).
fn write_summary_label<W: Write>(
    out: &mut W,
    prefix: &str,
    range: Option<(Boundary, Boundary)>,
    style: BandLabels,
) -> fmt::Result {
    out.write_str(prefix)?;
    if let Some((lo, hi)) = range {
        out.write_char(' ')?;
        write_trim_name(out, lo, style)?;
        if lo != hi {
            out.write_str("..")?;
            write_trim_name(out, hi, style)?;
        }
    }
    Ok(())
}

/// Right-align: pad to `width`, then the cell text.
fn cell<W: Write>(
    out: &mut W,
    width: usize,
    write: impl Fn(&mut CountWriter) -> fmt::Result + Copy,
    emit: impl Fn(&mut W) -> fmt::Result,
) -> fmt::Result {
    pad(out, width.saturating_sub(measure(write)))?;
    emit(out)
}

/// Render `table` into `out`: header, one row per populated
/// band, a blank line, then overall and trimmed mean/stdev
/// rows. Lines end with `\n`.
///
/// - `layout` fixes the column widths — [`Layout::measure`]
///   for snug columns, [`Layout::DEMO_LEGACY`] for the demo's
///   historical shape.
/// - The trimmed rows are omitted when nothing below the n2
///   cut is populated.
pub fn render_band_table<const CAP: usize, W: Write>(
    out: &mut W,
    table: &BandTable<CAP>,
    style: BandLabels,
    layout: &Layout,
) -> fmt::Result {
    let two_cell = layout.frac_width > 0;
    let label_region = layout.zpn_width + if two_cell { 1 + layout.frac_width } else { 0 };

    // Header row.
    pad(out, label_region)?;
    for name in ["first", "last", "range"] {
        out.write_char(' ')?;
        pad(out, layout.value_width.saturating_sub(name.len()))?;
        out.write_str(name)?;
    }
    out.write_char(' ')?;
    pad(out, layout.count_width.saturating_sub("count".len()))?;
    out.write_str("count")?;
    out.write_char(' ')?;
    pad(out, layout.value_width.saturating_sub("mean".len()))?;
    out.write_str("mean")?;
    out.write_char('\n')?;

    // Band rows.
    for (index, band) in table.bands().iter().enumerate() {
        if band.count == 0 {
            continue;
        }
        let Some(upper) = table.ladder().get(index + 1) else {
            continue;
        };
        if two_cell {
            let zpn_len = measure(|counter| write_zpn(counter, upper));
            write_zpn(out, upper)?;
            pad(out, layout.zpn_width.saturating_sub(zpn_len))?;
            out.write_char(' ')?;
            let show_frac = !matches!(upper, Boundary::Min | Boundary::Max);
            let frac_len = if show_frac {
                let len = measure(|counter| write_frac(counter, upper));
                write_frac(out, upper)?;
                len
            } else {
                0
            };
            pad(out, layout.frac_width.saturating_sub(frac_len))?;
        } else {
            let label_len = measure(|counter| write_label(counter, upper, style));
            write_label(out, upper, style)?;
            pad(out, layout.zpn_width.saturating_sub(label_len))?;
        }
        let mean = band.weighted_sum / band.count as f64;
        for value in [band.first, band.last, band.last - band.first] {
            out.write_char(' ')?;
            cell(
                out,
                layout.value_width,
                |counter| write_commas(counter, value),
                |sink| write_commas(sink, value),
            )?;
        }
        out.write_char(' ')?;
        cell(
            out,
            layout.count_width,
            |counter| write_commas(counter, band.count),
            |sink| write_commas(sink, band.count),
        )?;
        out.write_char(' ')?;
        cell(
            out,
            layout.value_width,
            |counter| write_commas_f64(counter, mean, layout.decimals),
            |sink| write_commas_f64(sink, mean, layout.decimals),
        )?;
        out.write_char('\n')?;
    }

    out.write_char('\n')?;

    // Summary rows: overall, then trimmed when populated.
    let overall = table.overall();
    summary_row(out, label_region, layout, "mean", None, style, overall.mean)?;
    summary_row(
        out,
        label_region,
        layout,
        "stdev",
        None,
        style,
        sqrt64(overall.variance),
    )?;
    if let Some(range) = table.trim_range() {
        let trimmed = table.trimmed();
        summary_row(
            out,
            label_region,
            layout,
            "mean",
            Some(range),
            style,
            trimmed.mean,
        )?;
        summary_row(
            out,
            label_region,
            layout,
            "stdev",
            Some(range),
            style,
            sqrt64(trimmed.variance),
        )?;
    }
    Ok(())
}

/// One summary row: label left in the label region, value
/// right in the first value column.
fn summary_row<W: Write>(
    out: &mut W,
    label_region: usize,
    layout: &Layout,
    prefix: &str,
    range: Option<(Boundary, Boundary)>,
    style: BandLabels,
    value: f64,
) -> fmt::Result {
    let label_len = measure(|counter| write_summary_label(counter, prefix, range, style));
    write_summary_label(out, prefix, range, style)?;
    pad(out, label_region.saturating_sub(label_len))?;
    out.write_char(' ')?;
    cell(
        out,
        layout.value_width,
        |counter| write_commas_f64(counter, value, layout.decimals),
        |sink| write_commas_f64(sink, value, layout.decimals),
    )?;
    out.write_char('\n')?;
}

#[cfg(test)]
#[allow(clippy::unwrap_used)] // OK: tests panic on setup failure by design
mod tests {
    use super::*;
    use crate::bands::{Ladder, RankSplit};
    use crate::{Config, Histogram};

    /// Render a boundary's zpn name to a String.
    fn zpn(boundary: Boundary) -> String {
        let mut out = String::new();
        write_zpn(&mut out, boundary).unwrap();
        out
    }

    /// Render a boundary's frac name to a String.
    fn frac(boundary: Boundary) -> String {
        let mut out = String::new();
        write_frac(&mut out, boundary).unwrap();
        out
    }

    /// Render a boundary's single-cell label to a String.
    fn label(boundary: Boundary, style: BandLabels) -> String {
        let mut out = String::new();
        write_label(&mut out, boundary, style).unwrap();
        out
    }

    /// The z4/n10 ladder's rendered labels must match
    /// iiac-perf's documented lists, both styles.
    #[test]
    fn labels_match_iiac_perf() {
        let ladder = Ladder::new(4, 10).unwrap();
        let zpn_names: Vec<String> = ladder.iter().map(zpn).collect();
        assert_eq!(
            zpn_names,
            [
                "min", "z4", "z3", "z2", "p10", "p20", "p30", "p40", "p50", "p60", "p70", "p80",
                "p90", "n2", "n3", "n4", "n5", "n6", "n7", "n8", "n9", "n10", "max",
            ]
        );
        let frac_names: Vec<String> = ladder.iter().map(frac).collect();
        assert_eq!(
            frac_names,
            [
                "min",
                "0.000_1",
                "0.001",
                "0.01",
                "0.10",
                "0.20",
                "0.30",
                "0.40",
                "0.50",
                "0.60",
                "0.70",
                "0.80",
                "0.90",
                "0.99",
                "0.999",
                "0.999_9",
                "0.999_99",
                "0.999_999",
                "0.999_999_9",
                "0.999_999_99",
                "0.999_999_999",
                "0.999_999_999_9",
                "max",
            ]
        );
    }

    /// `Both` pads zpn to 3 and appends the fraction;
    /// min/max collapse to the bare name.
    #[test]
    fn both_label_shapes() {
        assert_eq!(label(Boundary::N(4), BandLabels::Both), "n4  0.999_9");
        assert_eq!(
            label(Boundary::N(10), BandLabels::Both),
            "n10 0.999_999_999_9"
        );
        assert_eq!(label(Boundary::P(5), BandLabels::Both), "p50 0.50");
        assert_eq!(label(Boundary::Min, BandLabels::Both), "min");
        assert_eq!(label(Boundary::Max, BandLabels::Both), "max");
        assert_eq!(label(Boundary::Z(3), BandLabels::Zpn), "z3");
        assert_eq!(label(Boundary::Z(3), BandLabels::Frac), "0.001");
    }

    /// Trim names use the bare zpn form under `Both`.
    #[test]
    fn trim_name_bare() {
        let mut out = String::new();
        write_trim_name(&mut out, Boundary::Z(4), BandLabels::Both).unwrap();
        assert_eq!(out, "z4");
        out.clear();
        write_trim_name(&mut out, Boundary::N(2), BandLabels::Frac).unwrap();
        assert_eq!(out, "0.99");
    }

    /// Thousands separators, u64 end to end.
    #[test]
    fn commas_shapes() {
        let render = |value: u64| {
            let mut out = String::new();
            write_commas(&mut out, value).unwrap();
            out
        };
        assert_eq!(render(0), "0");
        assert_eq!(render(999), "999");
        assert_eq!(render(1_000), "1,000");
        assert_eq!(render(1_234_567), "1,234,567");
        assert_eq!(render(u64::MAX), "18,446,744,073,709,551,615");
    }

    /// Float formatting: rounding, zero padding, sign.
    #[test]
    fn commas_f64_shapes() {
        let render = |value: f64, decimals: usize| {
            let mut out = String::new();
            write_commas_f64(&mut out, value, decimals).unwrap();
            out
        };
        assert_eq!(render(1234.56, 1), "1,234.6");
        assert_eq!(render(0.95, 1), "1.0");
        assert_eq!(render(-12.345, 2), "-12.35");
        assert_eq!(render(0.0, 0), "0");
        assert_eq!(render(8.05, 1), "8.1");
        assert_eq!(render(1_000_000.0, 3), "1,000,000.000");
    }

    /// A fully predictable table (every value identical)
    /// renders byte-identically to the demo's format strings.
    #[test]
    fn render_matches_demo_format() {
        const CFG: Config = match Config::new(2, 8) {
            Ok(config) => config,
            Err(_) => panic!("invalid test config"),
        };
        const BUCKETS: usize = CFG.total_buckets();
        const LADDER: Ladder = match Ladder::new(2, 2) {
            Ok(ladder) => ladder,
            Err(_) => panic!("invalid test ladder"),
        };
        const CAP: usize = LADDER.band_count();

        let mut counts = [0u32; BUCKETS];
        let mut hist = Histogram::new(CFG, &mut counts).unwrap();
        hist.record_n(5, 10);
        let table: crate::BandTable<CAP> =
            crate::BandTable::build(LADDER, RankSplit::new(), || hist.buckets()).unwrap();

        let mut rendered = String::new();
        render_band_table(&mut rendered, &table, BandLabels::Both, &Layout::DEMO_LEGACY).unwrap();

        // Expected, straight from the demo's format strings.
        let mut expected = String::new();
        expected.push_str(&format!(
            "{:<4} {:<13} {:>14} {:>14} {:>14} {:>12} {:>14}\n",
            "", "", "first", "last", "range", "count", "mean"
        ));
        for decile in 1..=9u8 {
            expected.push_str(&format!(
                "{:<4} {:<13} {:>14} {:>14} {:>14} {:>12} {:>14}\n",
                format!("p{decile}0"),
                format!("0.{decile}0"),
                "5",
                "5",
                "0",
                "1",
                "5.0"
            ));
        }
        expected.push_str(&format!(
            "{:<4} {:<13} {:>14} {:>14} {:>14} {:>12} {:>14}\n",
            "max", "", "5", "5", "0", "1", "5.0"
        ));
        expected.push('\n');
        expected.push_str(&format!("{:<18} {:>14}\n", "mean", "5.0"));
        expected.push_str(&format!("{:<18} {:>14}\n", "stdev", "0.0"));
        expected.push_str(&format!("{:<18} {:>14}\n", "mean p10..p90", "5.0"));
        expected.push_str(&format!("{:<18} {:>14}\n", "stdev p10..p90", "5.0"));
        // The last line above is wrong on purpose? No — fix:
        assert_eq!(rendered, expected.replace("stdev p10..p90                5.0", "stdev p10..p90                0.0"));
    }

    /// Measured layout is snug and renders aligned rows.
    #[test]
    fn measured_layout() {
        const CFG: Config = match Config::new(2, 8) {
            Ok(config) => config,
            Err(_) => panic!("invalid test config"),
        };
        const BUCKETS: usize = CFG.total_buckets();
        const LADDER: Ladder = match Ladder::new(2, 2) {
            Ok(ladder) => ladder,
            Err(_) => panic!("invalid test ladder"),
        };
        const CAP: usize = LADDER.band_count();

        let mut counts = [0u32; BUCKETS];
        let mut hist = Histogram::new(CFG, &mut counts).unwrap();
        hist.record_n(5, 10);
        let table: crate::BandTable<CAP> =
            crate::BandTable::build(LADDER, RankSplit::new(), || hist.buckets()).unwrap();

        let layout = Layout::measure(&table, BandLabels::Both, 1);
        // Snug: zpn 3 ("p10"), value 5 ("first"), count 5
        // ("count"); frac widened so "stdev p10..p90" fits the
        // label region (3 + 1 + frac >= 14).
        assert_eq!(layout.zpn_width, 3);
        assert_eq!(layout.value_width, 5);
        assert_eq!(layout.count_width, 5);
        assert!(layout.zpn_width + 1 + layout.frac_width >= "stdev p10..p90".len());

        let mut rendered = String::new();
        render_band_table(&mut rendered, &table, BandLabels::Both, &layout).unwrap();
        // Header and band rows all share one width.
        let lines: Vec<&str> = rendered.lines().collect();
        let header_len = lines[0].len();
        for line in &lines[1..11] {
            assert_eq!(line.len(), header_len, "line: {line:?}");
        }
    }

    /// sqrt fallback sanity (also exercised via stdev cells).
    #[test]
    fn sqrt_values() {
        assert_eq!(sqrt64(0.0), 0.0);
        assert!((sqrt64(4.0) - 2.0).abs() < 1e-12);
        assert!((sqrt64(8.2) - 8.2f64.sqrt()).abs() < 1e-9);
    }
}

