1	//! Rendering: turn report structures into text.
2	//!
3	//! - The render side of the device/service split: `bands.rs` /
4	//!   `table.rs` build wire-friendly structures, this module
5	//!   turns them into characters. Everything writes into any
6	//!   `core::fmt::Write` — `no_std`-capable, no alloc — and a
7	//!   host caller just renders into a `String` and prints.
8	//! - Boundary labels live here, not on the data types: a
9	//!   label is presentation, and a device that ships structs
10	//!   never links this module's code.
11	//! - `render_band_table` reproduces the band-table shape the
12	//!   demo and iiac-perf print: header, one row per populated
13	//!   band (first/last/range/count/mean), then overall and
14	//!   tail-trimmed mean/stdev rows.
15	
16	use core::fmt::{self, Write};
17	
18	use crate::bands::Boundary;
19	use crate::table::BandTable;
20	
21	/// Band-label style for report rows.
22	///
23	/// - `Zpn` — nines/zeros + decile names (`z3`, `p50`, `n4`).
24	/// - `Frac` — literal boundary fractions with `_` grouping
25	///   (`0.001`, `0.50`, `0.999_9`).
26	/// - `Both` — zpn and fraction side by side; the juxtaposition
27	///   teaches the zpn vocabulary.
28	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
29	pub enum BandLabels {
30	    /// nines/zeros + decile names.
31	    Zpn,
32	    /// Literal fractions.
33	    Frac,
34	    /// zpn and fraction side by side.
35	    Both,
36	}
37	
38	impl BandLabels {
39	    /// Lowercase name for CLI flags and report-header
40	    /// metadata.
41	    pub const fn as_str(self) -> &'static str {
42	        match self {
43	            BandLabels::Zpn => "zpn",
44	            BandLabels::Frac => "frac",
45	            BandLabels::Both => "both",
46	        }
47	    }
48	}
49	
50	/// Write the nines/zeros / decile name (`z3`, `p50`, `n4`,
51	/// `min`).
52	pub fn write_zpn<W: Write>(out: &mut W, boundary: Boundary) -> fmt::Result {
53	    match boundary {
54	        Boundary::Min => out.write_str("min"),
55	        Boundary::Max => out.write_str("max"),
56	        Boundary::Z(k) => write!(out, "z{k}"),
57	        Boundary::P(d) => write!(out, "p{d}0"),
58	        Boundary::N(k) => write!(out, "n{k}"),
59	    }
60	}
61	
62	/// Write the literal-fraction name with `_` grouping
63	/// (`0.001`, `0.50`, `0.999_9`, `min`).
64	pub fn write_frac<W: Write>(out: &mut W, boundary: Boundary) -> fmt::Result {
65	    match boundary {
66	        Boundary::Min => out.write_str("min"),
67	        Boundary::Max => out.write_str("max"),
68	        Boundary::P(d) => write!(out, "0.{d}0"),
69	        Boundary::Z(k) => write_grouped(out, k, '0', true),
70	        Boundary::N(k) => write_grouped(out, k, '9', false),
71	    }
72	}
