74	/// Write the single-cell row label in the given style.
75	///
76	/// - `Both` pads the zpn name to its 3-char max so the
77	///   fraction column aligns (`n4  0.999_9`); `min`/`max`
78	///   carry no fraction, so `Both` prints them bare.
79	pub fn write_label<W: Write>(out: &mut W, boundary: Boundary, style: BandLabels) -> fmt::Result {
80	    match style {
81	        BandLabels::Zpn => write_zpn(out, boundary),
82	        BandLabels::Frac => write_frac(out, boundary),
83	        BandLabels::Both => match boundary {
84	            Boundary::Min | Boundary::Max => write_zpn(out, boundary),
