96	/// Write the bare style-name used in a trimmed-stat range
97	/// label — `Both` reuses the zpn name (`z4`, not the padded
98	/// pair) so it reads cleanly in a `z4..n2` range.
99	pub fn write_trim_name<W: Write>(
100	    out: &mut W,
101	    boundary: Boundary,
102	    style: BandLabels,
103	) -> fmt::Result {
104	    match style {
105	        BandLabels::Frac => write_frac(out, boundary),
106	        BandLabels::Zpn | BandLabels::Both => write_zpn(out, boundary),
107	    }
108	}
