110	/// Write `0.` then `digit_count` digits of `fill`, `_`-grouped
111	/// in threes; `trailing_one` replaces the last digit with `1`
112	/// (the zK fractions: `0.000_1`).
113	fn write_grouped<W: Write>(
114	    out: &mut W,
115	    digit_count: u8,
116	    fill: char,
117	    trailing_one: bool,
118	) -> fmt::Result {
119	    out.write_str("0.")?;
120	    let mut index = 0u8;
121	    while index < digit_count {
122	        if index > 0 && index.is_multiple_of(3) {
123	            out.write_char('_')?;
124	        }
125	        let last = index + 1 == digit_count;
126	        out.write_char(if trailing_one && last { '1' } else { fill })?;
127	        index += 1;
128	    }
129	    Ok(())
130	}
