132	/// Write a non-negative integer with thousands separators,
133	/// `12345` → `12,345`.
134	pub fn write_commas<W: Write>(out: &mut W, value: u64) -> fmt::Result {
135	    let mut digits = [0u8; 20];
136	    let mut len = 0usize;
137	    let mut rest = value;
138	    loop {
139	        if let Some(slot) = digits.get_mut(len) {
140	            *slot = b'0' + (rest % 10) as u8;
141	        }
142	        len += 1;
143	        rest /= 10;
144	        if rest == 0 {
145	            break;
146	        }
147	    }
148	    let mut index = len;
149	    while index > 0 {
150	        index -= 1;
151	        if let Some(&digit) = digits.get(index) {
152	            out.write_char(digit as char)?;
153	        }
154	        if index > 0 && index.is_multiple_of(3) {
155	            out.write_char(',')?;
156	        }
157	    }
158	    Ok(())
159	}
