161	/// Write a float with `decimals` fractional digits (rounded)
162	/// and thousands separators on the integer part. Scaled
163	/// integer math — no `round`/`floor` from `std`; `decimals`
164	/// is clamped to 18 so the scale stays in u128.
165	pub fn write_commas_f64<W: Write>(out: &mut W, value: f64, decimals: usize) -> fmt::Result {
166	    if !value.is_finite() {
167	        return write!(out, "{value}");
168	    }
169	    let decimals = if decimals > 18 { 18 } else { decimals };
170	    let negative = value < 0.0;
171	    if negative {
172	        out.write_char('-')?;
173	    }
174	    let magnitude = if negative { -value } else { value };
175	    let mut scale = 1u128;
176	    let mut index = 0;
177	    while index < decimals {
