184	        return write!(out, "{magnitude:.decimals$}");
185	    }
186	    let scaled = scaled_f as u128;
187	    let int_part = scaled / scale;
188	    let int_part = if int_part > u64::MAX as u128 {
189	        u64::MAX
190	    } else {
191	        int_part as u64
192	    };
193	    write_commas(out, int_part)?;
194	    if decimals > 0 {
195	        out.write_char('.')?;
196	        let frac_part = scaled % scale;
197	        let mut divisor = scale / 10;
198	        while divisor > 0 {
199	            out.write_char((b'0' + (frac_part / divisor % 10) as u8) as char)?;
200	            divisor /= 10;
201	        }
202	    }
203	    Ok(())
204	}
