1	//! Rendering: turn report structures into text. `std`-only.
2	//!
3	//! - The render side of the device/service split: a device
4	//!   ships the `no_std` structures (`bands.rs`, `table.rs`);
5	//!   the service — always a host with `std` — turns them into
6	//!   text. Gating the whole module on `std` states that
7	//!   architecture at the crate boundary and keeps the code on
8	//!   plain `String`/`format!`.
9	//! - Boundary labels live here, not on the data types: a
10	//!   label is presentation, and a device that ships structs
11	//!   never links this module.
12	//! - `render_band_table` reproduces the band-table shape the
13	//!   demo and iiac-perf print: header, one row per populated
14	//!   band (first/last/range/count/mean), then overall and
15	//!   tail-trimmed mean/stdev rows.
16	
17	use crate::bands::Boundary;
18	use crate::table::BandTable;
19	
20	/// Band-label style for report rows.
21	///
22	/// - `Zpn` — nines/zeros + decile names (`z3`, `p50`, `n4`).
23	/// - `Frac` — literal boundary fractions with `_` grouping
24	///   (`0.001`, `0.50`, `0.999_9`).
25	/// - `Both` — zpn and fraction side by side; the juxtaposition
26	///   teaches the zpn vocabulary.
27	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
28	pub enum BandLabels {
29	    /// nines/zeros + decile names.
30	    Zpn,
31	    /// Literal fractions.
32	    Frac,
33	    /// zpn and fraction side by side.
34	    Both,
35	}
36	
37	impl BandLabels {
38	    /// Lowercase name for CLI flags and report-header
39	    /// metadata.
40	    pub const fn as_str(self) -> &'static str {
41	        match self {
42	            BandLabels::Zpn => "zpn",
43	            BandLabels::Frac => "frac",
44	            BandLabels::Both => "both",
45	        }
46	    }
47	}
48	
49	/// The nines/zeros / decile name (`z3`, `p50`, `n4`, `min`).
50	pub fn zpn_label(boundary: Boundary) -> String {
51	    match boundary {
52	        Boundary::Min => "min".to_string(),
53	        Boundary::Max => "max".to_string(),
54	        Boundary::Z(k) => format!("z{k}"),
55	        Boundary::P(d) => format!("p{d}0"),
56	        Boundary::N(k) => format!("n{k}"),
57	    }
58	}
59	
60	/// The literal-fraction name with `_` grouping (`0.001`,
61	/// `0.50`, `0.999_9`, `min`).
62	pub fn frac_label(boundary: Boundary) -> String {
63	    match boundary {
64	        Boundary::Min => "min".to_string(),
65	        Boundary::Max => "max".to_string(),
66	        Boundary::P(d) => format!("0.{d}0"),
67	        Boundary::Z(k) => grouped(k, '0', true),
68	        Boundary::N(k) => grouped(k, '9', false),
69	    }
70	}
71	
72	/// The single-cell row label in the given style.
73	///
74	/// - `Both` pads the zpn name to its 3-char max so the
75	///   fraction column aligns (`n4  0.999_9`); `min`/`max`
76	///   carry no fraction, so `Both` prints them bare.
77	pub fn boundary_label(boundary: Boundary, style: BandLabels) -> String {
78	    match style {
79	        BandLabels::Zpn => zpn_label(boundary),
80	        BandLabels::Frac => frac_label(boundary),
81	        BandLabels::Both => match boundary {
82	            Boundary::Min | Boundary::Max => zpn_label(boundary),
83	            _ => format!("{:<3} {}", zpn_label(boundary), frac_label(boundary)),
84	        },
85	    }
86	}
87	
88	/// The bare style-name used in a trimmed-stat range label —
89	/// `Both` reuses the zpn name (`z4`, not the padded pair) so
90	/// it reads cleanly in a `z4..n2` range.
91	pub fn trim_name(boundary: Boundary, style: BandLabels) -> String {
92	    match style {
93	        BandLabels::Frac => frac_label(boundary),
94	        BandLabels::Zpn | BandLabels::Both => zpn_label(boundary),
95	    }
96	}
97	
98	/// `0.` then `digit_count` digits of `fill`, `_`-grouped in
99	/// threes; `trailing_one` replaces the last digit with `1`
100	/// (the zK fractions: `0.000_1`).
101	fn grouped(digit_count: u8, fill: char, trailing_one: bool) -> String {
102	    let mut out = String::from("0.");
103	    for index in 0..digit_count {
104	        if index > 0 && index.is_multiple_of(3) {
105	            out.push('_');
106	        }
107	        let last = index + 1 == digit_count;
108	        out.push(if trailing_one && last { '1' } else { fill });
109	    }
110	    out
111	}
112	
113	/// Format an integer with thousands separators,
114	/// `12345` → `"12,345"`.
115	pub fn fmt_commas(value: u64) -> String {
116	    let digits = value.to_string();
117	    let mut out = String::with_capacity(digits.len() + digits.len() / 3);
118	    for (index, ch) in digits.chars().rev().enumerate() {
119	        if index > 0 && index.is_multiple_of(3) {
120	            out.push(',');
121	        }
122	        out.push(ch);
123	    }
124	    out.chars().rev().collect()
125	}
126	
127	/// Format a float with `decimals` fractional digits and
128	/// thousands separators on the integer part. Non-numeric or
129	/// beyond-u64 integer parts come back plain (no grouping).
130	pub fn fmt_commas_f64(value: f64, decimals: usize) -> String {
131	    let text = format!("{value:.decimals$}");
132	    let (sign, body) = match text.strip_prefix('-') {
133	        Some(rest) => ("-", rest),
134	        None => ("", text.as_str()),
135	    };
136	    let (int_part, frac_part) = match body.find('.') {
137	        Some(dot) => (&body[..dot], &body[dot..]),
138	        None => (body, ""),
139	    };
140	    match int_part.parse::<u64>() {
141	        Ok(int_num) => format!("{sign}{}{frac_part}", fmt_commas(int_num)),
142	        Err(_) => text.clone(),
143	    }
144	}
145	
146	/// Column widths for [`render_band_table`], in characters.
147	///
148	/// - `zpn_width` — the (first) label cell; single-cell styles
149	///   put their whole label here.
150	/// - `frac_width` — the second label cell; used by
